        fn map_on_empty_vector() {
            let vec: BoundedVec<u32, 5> = BoundedVec::new();
            let result = vec.map(|x| x * 2);
            assert_eq(result, vec);
            assert_eq(result.len(), 0);
            assert_eq(result.max_len(), 5);
        }
    }

