use crate::protocol::{
    abis::function_selector::FunctionSelector,
    address::AztecAddress,
    constants::{
        DOM_SEP__INITIALIZER, DOM_SEP__PRIVATE_INITIALIZATION_NULLIFIER, DOM_SEP__PUBLIC_INITIALIZATION_NULLIFIER,
    },
    hash::poseidon2_hash_with_separator,
    traits::ToField,
};
use std::meta::{ctstring::AsCtString, unquote};

use crate::{
    context::{PrivateContext, PublicContext, UtilityContext},
    macros::{
        internals_functions_generation::external_functions_registry::get_public_functions, utils::fn_has_noinitcheck,
    },
    nullifier::utils::compute_nullifier_existence_request,
    oracle::{
        get_contract_instance::{
            get_contract_instance, get_contract_instance_deployer_avm, get_contract_instance_initialization_hash_avm,
        },
        nullifiers::check_nullifier_exists,
    },
};

/// The name of the auto-generated function that emits the public initialization nullifier.
///
/// This function is injected into the public dispatch table for contracts with initializers.
pub(crate) comptime global EMIT_PUBLIC_INIT_NULLIFIER_FN_NAME: Quoted = quote { __emit_public_init_nullifier };

/// Returns `true` if the module has any public functions that require initialization checks (i.e. that don't have
/// `#[noinitcheck]`). If all public functions skip initialization checks, there's no point emitting the public
/// initialization nullifier since nothing will check it.
pub(crate) comptime fn has_public_init_checked_functions(m: Module) -> bool {
    get_public_functions(m).any(|f: FunctionDefinition| !fn_has_noinitcheck(f))
}

/// Selector for `EMIT_PUBLIC_INIT_NULLIFIER_FN_NAME`, derived at comptime so it stays in sync.
global EMIT_PUBLIC_INIT_NULLIFIER_SELECTOR: FunctionSelector = comptime {
    let name = EMIT_PUBLIC_INIT_NULLIFIER_FN_NAME;
    let sig = f"{name}()".as_ctstring();
    unquote!(quote { FunctionSelector::from_signature($sig) })
};

/// Emits (only) the public initialization nullifier.
///
/// This function is called by the aztec-nr auto-generated external public contract function (enqueued by private
/// [`initializer`](crate::macros::functions::initializer) functions), and also by
/// [`mark_as_initialized_from_public_initializer`] for public initializers.
///
/// # Warning
///
/// This should not be called manually. Incorrect use can leave the contract in a broken initialization state (e.g.
/// emitting the public nullifier without the private one). The macro-generated code handles this automatically.
pub fn mark_as_initialized_public(context: PublicContext) {
    let init_nullifier = compute_public_initialization_nullifier(context.this_address());
    context.push_nullifier_unsafe(init_nullifier);
}

fn mark_as_initialized_private(context: &mut PrivateContext) {
    let address = (*context).this_address();
    let instance = get_contract_instance(address);
    let init_nullifier = compute_private_initialization_nullifier(address, instance.initialization_hash);
    context.push_nullifier_unsafe(init_nullifier);
}

/// Emits the private initialization nullifier and, if relevant, enqueues the emission of the public one.
///
/// If the contract has public functions that perform initialization checks (i.e. that don't have `#[noinitcheck]`),
/// this also enqueues a call to the auto-generated `__emit_public_init_nullifier` function so the public
/// initialization nullifier is emitted in public. Called by private
/// [`initializer`](crate::macros::functions::initializer) macros.
pub fn mark_as_initialized_from_private_initializer(context: &mut PrivateContext, emit_public_init_nullifier: bool) {
    mark_as_initialized_private(context);
    if emit_public_init_nullifier {
        context.call_public_function((*context).this_address(), EMIT_PUBLIC_INIT_NULLIFIER_SELECTOR, [], false);
    }
}

/// Emits both initialization nullifiers (private and public).
///
/// Called by public [`initializer`](crate::macros::functions::initializer) macros, since public initializers must set
/// both so that both private and public functions see the contract as initialized.
pub fn mark_as_initialized_from_public_initializer(context: PublicContext) {
    let address = context.this_address();
    // `get_contract_instance_initialization_hash_avm` returns None when there is no deployed contract instance at the
    // given address. This cannot happen here because we're querying `this_address()`, i.e. the contract that is
    // currently executing, which by definition must have been deployed.
    let init_hash = get_contract_instance_initialization_hash_avm(address).unwrap();
    let private_nullifier = compute_private_initialization_nullifier(address, init_hash);
    context.push_nullifier_unsafe(private_nullifier);
    mark_as_initialized_public(context);
}

/// Asserts that the contract has been initialized, from public's perspective.
///
/// Checks that the public initialization nullifier exists.
// All external public contract functions will call this function (except those marked as #[no_init]), so we
// want to make sure that we don't include a copy of its body for each of them.
#[inline_never]
pub unconstrained fn assert_is_initialized_public(context: PublicContext) {
    let init_nullifier = compute_public_initialization_nullifier(context.this_address());
    // Safety: the public initialization nullifier is only ever emitted by public functions, and so the timing
    // concerns from nullifier_exists_unsafe do not apply. Additionally, it is emitted after all initializer
    // functions have run, so initialization is guaranteed to be complete by the time it exists.
    assert(context.nullifier_exists_unsafe(init_nullifier, context.this_address()), "Not initialized");
}

/// Asserts that the contract has been initialized, from private's perspective.
///
/// Checks that the private initialization nullifier exists.
pub fn assert_is_initialized_private(context: &mut PrivateContext) {
    let address = context.this_address();
    let instance = get_contract_instance(address);
    let init_nullifier = compute_private_initialization_nullifier(address, instance.initialization_hash);
    let nullifier_existence_request = compute_nullifier_existence_request(init_nullifier, address);
    context.assert_nullifier_exists(nullifier_existence_request);
}

/// Asserts that the contract has been initialized, from a utility function's perspective.
///
/// Only checks the private initialization nullifier in the settled nullifier tree. Since both nullifiers are
/// emitted in the same transaction, the private nullifier's presence in settled state guarantees the public one
/// is also settled.
pub unconstrained fn assert_is_initialized_utility(context: UtilityContext) {
    let address = context.this_address();
    let instance = get_contract_instance(address);
    let initialization_nullifier = compute_private_initialization_nullifier(address, instance.initialization_hash);
    assert(check_nullifier_exists(initialization_nullifier), "Not initialized");
}

/// Computes the private initialization nullifier for a contract.
///
/// Including `init_hash` ensures that an observer who knows only the contract address cannot reconstruct this value
/// and scan the nullifier tree to determine initialization status. `init_hash` is only known to parties that hold
/// the contract instance.
pub fn compute_private_initialization_nullifier(address: AztecAddress, init_hash: Field) -> Field {
    poseidon2_hash_with_separator(
        [address.to_field(), init_hash],
        DOM_SEP__PRIVATE_INITIALIZATION_NULLIFIER,
    )
}

fn compute_public_initialization_nullifier(address: AztecAddress) -> Field {
    poseidon2_hash_with_separator(
        [address.to_field()],
        DOM_SEP__PUBLIC_INITIALIZATION_NULLIFIER,
    )
}

// Called by code injected by the macros in `macros/internals_functions_generation/external/public.nr`.
pub fn assert_initialization_matches_address_preimage_public(context: PublicContext) {
    let address = context.this_address();
    let deployer = get_contract_instance_deployer_avm(address).unwrap();
    let initialization_hash = get_contract_instance_initialization_hash_avm(address).unwrap();
    let expected_init = compute_initialization_hash(context.selector(), context.get_args_hash());
    assert(initialization_hash == expected_init, "Initialization hash does not match");
    assert(
        (deployer.is_zero()) | (deployer == context.maybe_msg_sender().unwrap()),
        "Initializer address is not the contract deployer",
    );
}

// Called by code injected by the macros in `macros/internals_functions_generation/external/private.nr`.
pub fn assert_initialization_matches_address_preimage_private(context: PrivateContext) {
    let address = context.this_address();
    let instance = get_contract_instance(address);
    let expected_init = compute_initialization_hash(context.selector(), context.get_args_hash());
    assert(instance.initialization_hash == expected_init, "Initialization hash does not match");
    assert(
        (instance.deployer.is_zero()) | (instance.deployer == context.maybe_msg_sender().unwrap()),
        "Initializer address is not the contract deployer",
    );
}

/// This function is not only used in macros but it's also used by external people to check that an instance has been
/// initialized with the correct constructor arguments. Don't hide this unless you implement factory functionality.
pub fn compute_initialization_hash(init_selector: FunctionSelector, init_args_hash: Field) -> Field {
    poseidon2_hash_with_separator(
        [init_selector.to_field(), init_args_hash],
        DOM_SEP__INITIALIZER,
    )
}

118.source:
use crate::macros::{
    internals_functions_generation::external::helpers::{create_authorize_once_check, get_abi_relevant_attributes},
    utils::{
        fn_has_authorize_once, fn_has_noinitcheck, is_fn_initializer, is_fn_only_self, is_fn_view,
        module_has_initializer, module_has_storage,
    },
};

/// Emits a per-contract helper that creates the `self` value from a `PublicContext` already in scope.
///
/// This is the shared helper used by both:
/// - public external functions, via [`generate_public_self_creator`], which constructs a fresh `PublicContext` from
///   `calldata_copy` and then delegates to this helper; and
/// - public internal functions and `#[contract_library_method]` bodies, which already receive `context` as a
///   parameter and call this helper directly to skip the `calldata_copy` step.
pub(crate) comptime fn generate_public_self_creator_from_context(m: Module) -> Quoted {
    let (storage_type, storage_init) = if module_has_storage(m) {
        (quote { Storage<aztec::context::PublicContext> }, quote { let storage = Storage::init(context); })
    } else {
        // Contract does not have Storage defined, so we set storage to the unit type `()`. ContractSelfPublic requires
        // a storage struct in its constructor. Using an Option type would lead to worse developer experience and
        // higher constraint counts so we use the unit type `()` instead.
        (quote { () }, quote { let storage = (); })
    };

    quote {
        #[contract_library_method]
        unconstrained fn __aztec_nr_internals__create_public_self_from_context(context: aztec::context::PublicContext) -> aztec::contract_self::ContractSelfPublic<$storage_type, CallSelf<aztec::context::PublicContext>, CallSelfStatic<aztec::context::PublicContext>, CallInternal<aztec::context::PublicContext>> {
            $storage_init
            let self_address = context.this_address();
            let call_self: CallSelf<aztec::context::PublicContext> = CallSelf { address: self_address, context };
            let call_self_static: CallSelfStatic<aztec::context::PublicContext> = CallSelfStatic { address: self_address, context };
            let internal: CallInternal<aztec::context::PublicContext> = CallInternal { context };
            aztec::contract_self::ContractSelfPublic::new(context, storage, call_self, call_self_static, internal)
        }
    }
}

/// Generates the per-contract helper that builds public `self`.
///
/// Each public external function calls this helper instead of inlining the construction, so the same preamble does not
/// appear duplicated in every public function body. We let Noir's inliner decide whether to inline the helper at each
/// call site rather than forcing it via macro expansion.
///
/// The helper is generic over the calldata length `N` because `PublicContext::new` takes a closure that reads `N`
/// fields from calldata. Noir monomorphizes one copy per distinct `N`, so public functions with the same number of
/// serialized args reuse the same compiled code.
pub(crate) comptime fn generate_public_self_creator(m: Module) -> Quoted {
    let storage_type = if module_has_storage(m) {
        quote { Storage<aztec::context::PublicContext> }
    } else {
        quote { () }
    };

    quote {
        #[contract_library_method]
        unconstrained fn __aztec_nr_internals__create_public_self<let N: u32>() -> aztec::contract_self::ContractSelfPublic<$storage_type, CallSelf<aztec::context::PublicContext>, CallSelfStatic<aztec::context::PublicContext>, CallInternal<aztec::context::PublicContext>> {
            // Unlike in the private case, in public the `context` does not need to receive the hash of the original
            // params.
            let context = aztec::context::PublicContext::new(|| {
                // We start from 1 because we skip the selector for the dispatch function.
                let serialized_args : [Field; N] = aztec::oracle::avm::calldata_copy(1, N);
                aztec::hash::hash_args(serialized_args)
            });
            __aztec_nr_internals__create_public_self_from_context(context)
        }
    }
}

pub(crate) comptime fn generate_public_external(f: FunctionDefinition) -> Quoted {
    let module_has_initializer = module_has_initializer(f.module());

    // Public functions undergo a lot of transformations from their Aztec.nr form.
    let original_params = f.parameters();

    let args_len_quote = if original_params.len() == 0 {
        // If the function has no parameters, we set the args_len to 0.
        quote { 0 }
    } else {
        // The following will give us <type_of_struct_member_1 as Serialize>::N + <type_of_struct_member_2 as
        // Serialize>::N + ...
        original_params
            .map(|(_, param_type): (Quoted, Type)| {
                quote {
            <$param_type as $crate::protocol::traits::Serialize>::N
        }
            })
            .join(quote {+})
    };

    let contract_self_creation = quote {
        #[allow(unused_variables)]
        let mut self = __aztec_nr_internals__create_public_self::<$args_len_quote>();
    };

    let original_function_name = f.name();

    // Modifications introduced by the different marker attributes.
    let internal_check = if is_fn_only_self(f) {
        let assertion_message = f"Function {original_function_name} can only be called by the same contract";
        quote { assert(self.msg_sender() == self.address, $assertion_message); }
    } else {
        quote {}
    };

    let view_check = if is_fn_view(f) {
        let assertion_message = f"Function {original_function_name} can only be called statically".as_quoted_str();
        quote { assert(self.context.is_static_call(), $assertion_message); }
    } else {
        quote {}
    };

    let (assert_initializer, mark_as_initialized) = if is_fn_initializer(f) {
        (
            quote {
                aztec::macros::functions::initialization_utils::assert_initialization_matches_address_preimage_public(self.context);
            },
            quote {
                aztec::macros::functions::initialization_utils::mark_as_initialized_from_public_initializer(self.context);
            },
        )
    } else {
        (quote {}, quote {})
    };

    // Initialization checks are not included in contracts that don't have initializers.
    let init_check = if module_has_initializer & !fn_has_noinitcheck(f) & !is_fn_initializer(f) {
        quote { aztec::macros::functions::initialization_utils::assert_is_initialized_public(self.context); }
    } else {
        quote {}
    };

    // Inject the authwit check if the function is marked with #[authorize_once].
    let authorize_once_check = if fn_has_authorize_once(f) {
        create_authorize_once_check(f, false)
    } else {
        quote {}
    };

    let to_prepend = quote {
        $contract_self_creation
        $assert_initializer
        $init_check
        $internal_check
        $view_check
        $authorize_once_check
    };

    // `mark_as_initialized` is placed after the user's function body. If it ran at the beginning, the contract
    // would appear initialized while the initializer is still running, allowing contracts called by the initializer
    // to re-enter into a half-initialized contract.
    let to_append = quote {
        $mark_as_initialized
    };

    let fn_name = f"__aztec_nr_internals__{original_function_name}".quoted_contents();
    let body = f.body();
    let return_type = f.return_type();

    // New function parameters are the same as the original function's ones.
    let params = original_params.map(|(param_name, param_type)| quote { $param_name: $param_type }).join(quote {, });

    // Preserve all attributes that are relevant to the function's ABI.
    let abi_relevant_attributes = get_abi_relevant_attributes(f);

    // All public functions are automatically made unconstrained, even if they were not marked as such. This is because
    // instead of compiling into a circuit, they will compile to bytecode that will be later transpiled into AVM
    // bytecode.
    quote {
        #[aztec::macros::internals_functions_generation::abi_attributes::abi_public]
        $abi_relevant_attributes
        unconstrained fn $fn_name($params) -> pub $return_type {
            $to_prepend
            $body
            $to_append
        }
    }
}

